  // ── op_single_kind + op_missing_kind ──────────────────────────────────────

  describe("op_single_kind", () => {
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_17
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability:Products.A10nBlueprintEngine.Features.SystemAuthoring.op_single_kind:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_spec_references:Products.A10nBlueprintEngine.Features.SystemAuthoring.op_single_kind:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability_2
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_operation_reachability_3
    it("op carrying exactly one kind decorator (@tool) — no op-single-kind", async () => {
      await ruleTester
        .expect(`
          ${INV}
          @component(#{ type: ComponentType.Store })
          namespace Components.DataStore {
            model Row { id: string; }
          }
          @component(#{ type: ComponentType.Agent })
          @dependsOn([Components.DataStore])
          namespace Components.MyAgent {
            @tool(#{ sequential: false })
            @reads([Components.DataStore.Row])
            op analyze(): void;

            @graph
            namespace Graph {
              model S { x: string; }
              @node(#{ is_entrypoint: true })
              @calls([Components.MyAgent.analyze])
              op entry(s: S): Command<{}, End>;
              @node op done(s: S): Command<{}, End>;
            }
          }
        `)
        .toBeValid();
    });

    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T008.T008_18
    it("op carrying @tool and @node — emits opSingleKind", async () => {
      await ruleTester
        .expect(`
          ${INV}
          @component(#{ type: ComponentType.Agent })
          namespace Components.MyAgent {
            @graph
            namespace Graph {
              model S { x: string; }
              @node(#{ is_entrypoint: true })
              @tool(#{ sequential: false })
              op bad(): void;
              @node op done(s: S): Command<PickProperties<S, "x">, End>;
            }
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/operation-reachability", message: /conflicting kind/ },
          { code: "@a10n/blueprint-typespec/operation-reachability", message: /@tool op.*no @calls/ },
        ]);
    });
  });

  describe("op_missing_kind", () => {
    it("plain op in Service with no kind decorator — emits opMissingKind", async () => {
      await ruleTester
        .expect(`
          ${INV}
          @component(#{ type: ComponentType.Service })
          namespace Components.MyService {
            op bare_op(): void;
          }
        `)
        .toEmitDiagnostics([
          { code: "@a10n/blueprint-typespec/operation-reachability", message: /no op-kind decorator/ },
          { code: "@a10n/blueprint-typespec/operation-reachability", message: /no @calls/ },
        ]);
    });

    it("ui_action op inside @uiRoute — no opMissingKind (uiRoute namespace is kind signal)", async () => {
      const runner = await Tester.createInstance();
      // Use runner.diagnose to avoid failing on other unrelated diagnostics
      // (uiActionMissingEdge etc. that fire on minimal fixtures)
      const diagnostics = await runner.diagnose(`
        ${INV}
        @component(#{ type: ComponentType.Ui })
        namespace Components.MyUi {
          @uiRoute(#{ path: "/home" })
          namespace Routes.Home {
            op on_mount(): UiCommand<Components.MyUi.Routes.Home.LocalState>;
            model LocalState { ready: boolean; }
          }
        }
      `);
      const kindDiags = diagnostics.filter(
        (d) => d.code === "@a10n/blueprint-typespec/operation-reachability" &&
          String(d.message).includes("no op-kind decorator")
      );
      if (kindDiags.length > 0) throw new Error(`Expected no opMissingKind but got: ${kindDiags[0]?.message}`);
    });
  });

